var e=JSON.parse(`[{"id":"L5_1","type":"dialog","speaker":null,"text":{"KOREA":"이해를 바라지는 않는다.","JPN":"理解を求めてはいない。","ENG":"I do not wish for understanding.","TWN":"我不奢望有人理解。"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_TRAGEDY_HARD","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L6_1","type":"dialog","speaker":null,"text":{"KOREA":"신앙을 부르짖는 자들은, 그냥 거기 그대로 있으면 돼.","JPN":"信仰を叫ぶ者たちは、そのままそこにいれば十分。","ENG":"Those who cry out for faith shall stay as they are.","TWN":"那些打著信仰旗幟的人，只需要隔岸觀火。"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_TRAGEDY_HARD","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L7_1","type":"dialog","speaker":null,"text":{"KOREA":"그들의 눈으로 본 아름다운 세상을 내게 속삭여 줄 테니까.","JPN":"彼らの目で見たキレイな世界を私に囁いてくれるだろうから。","ENG":"For they shall whisper to me about the beautiful world of which they have seen with their own eyes.","TWN":"因為他們眼睛所見的美麗世界會向我私語。"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_TRAGEDY_HARD","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L13_1","type":"dialog","speaker":null,"text":{"KOREA":"결국 교단 내에서 누군가는 해야 할 일이다.","JPN":"結局教団の誰かはやるべきことだ。","ENG":"For someone in the Order needs take this responsibility.","TWN":"教團內終究必須有人來做這件事。"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"CUTSCENE_TRAGEDY_HARD","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L14_1","type":"dialog","speaker":null,"text":{"KOREA":"그러니 신앙을 부르짖는 자들은, 그냥 거기 그대로 있으면 돼.","JPN":"だから、信仰を叫ぶ者たちは、そのままそこにいれば十分。","ENG":"So those who cry out for faith shall stay as they are.","TWN":"那些打著信仰旗幟的人，只需要隔岸觀火。"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"CUTSCENE_TRAGEDY_HARD","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L15_1","type":"dialog","speaker":null,"text":{"KOREA":"신성을 모욕하고 세상의 증오를 받아 마땅한 일은 내게 맡기소서.","JPN":"神聖を侮辱し、世界に憎悪されるべき仕事は私にお任せください。","ENG":"For I shall take upon myself the hatred of this world, and perform such acts that insult the gods.","TWN":"會玷汙神聖，遭世界憎恨的事，就交給我吧。"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"CUTSCENE_TRAGEDY_HARD","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L21_1","type":"dialog","speaker":null,"text":{"KOREA":"거리에서 죽었어야 할 내 목숨을 위대한 정적이 건져 올리셨으니.","JPN":"街で死んでいたはずの私の命を、偉大な静寂がお救いになった。","ENG":"My life should have died on the streets, but the Great Silence rescued me.","TWN":"是偉大的寂靜在街上將瀕死的我給救回來的。"},"stage":{"bg":"HARMONY_05","bgm":"CUTSCENE_TRAGEDY_HARD","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L22_1","type":"dialog","speaker":null,"text":{"KOREA":"이제 그 뜻대로 쓰임 받을지어다.","JPN":"御心のままにお使いになるだろう。","ENG":"Use me to accomplish your will.","TWN":"現在我要按著她的意思而為。"},"stage":{"bg":"HARMONY_05","bgm":"CUTSCENE_TRAGEDY_HARD","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L26_1","type":"dialog","speaker":"SENA_HARMONY_NULL_NULL","text":{"KOREA":"지휘자님? 예하께서 방문하셨어요.","JPN":"マエストロ？　猊下がお見えになりました。","ENG":"Maestra Nequitia? Eminence has arrived.","TWN":"指揮家？主教來訪。"},"stage":{"bg":"LABORATORY_02","bgm":"CUTSCENE_TRAGEDY_HARD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SENA_HARMONY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"SENA_HARMONY_NULL_NULL","text":{"KOREA":"심문관들을 대동하지는 않았는데…… 어떻게 할까요?","JPN":"尋問官は一緒ではありませんが……どういたしましょうか。","ENG":"She is not accompanied by the inquisition... What should we do?","TWN":"沒有審訊官同行……該怎麼辦呢？"},"stage":{"bg":"LABORATORY_02","bgm":"CUTSCENE_TRAGEDY_HARD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SENA_HARMONY_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"CONDUCT_HARMONY_NULL_NULL","text":{"KOREA":"오늘은 음색이 유독 아름답더니 반가운 손님이 오시기 때문이군요.","JPN":"今日はひときわ音色が美しいと思ったら、懐かしいお客様が訪ねてくださったのですね。","ENG":"Music is especially beautiful, for today, we have a special guest.","TWN":"怪不得今天的音色特別悅耳，原來是有貴賓造訪。"},"stage":{"bg":"LABORATORY_02","bgm":"CUTSCENE_TRAGEDY_HARD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CONDUCT_HARMONY_NULL_NULL","face":"UNIT_LAUGH"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L30_1","type":"dialog","speaker":"CONDUCT_HARMONY_NULL_NULL","text":{"KOREA":"예하께서 바깥 바람을 오래 쐬시게 하는 건 예의가 아니지요.","JPN":"猊下を長らく外の空気にお晒しすることは礼儀ではありません。","ENG":"It is not polite to make her wait for such a long time.","TWN":"讓主教在外面乾等不是待客之道，"},"stage":{"bg":"LABORATORY_02","bgm":"CUTSCENE_TRAGEDY_HARD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CONDUCT_HARMONY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"CONDUCT_HARMONY_NULL_NULL","text":{"KOREA":"안으로 모시세요. 제가 직접 응대하겠습니다.","JPN":"中へご案内しなさい。私がじきに接待しましょう。","ENG":"Let her in. I shall take care of it personally.","TWN":"快請她進來，我親自來接待她。"},"stage":{"bg":"LABORATORY_02","bgm":"CUTSCENE_TRAGEDY_HARD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CONDUCT_HARMONY_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"MORS_SHADOW_ARMOR_NULL","text":{"KOREA":"……마에스트로, 대답을 전하러 왔다.","JPN":"……マエストロ、答えを伝えに来た。","ENG":"...Maestra, I have arrived with an answer.","TWN":"……指揮家，我是來回答你的。"},"stage":{"bg":"LABORATORY_02","bgm":"CUTSCENE_TRAGEDY_HARD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CONDUCT_HARMONY_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_COMBAT_ALL_FOOT_STEP_LANDING_SMALL"},{"id":"L37_1","type":"dialog","speaker":"CONDUCT_HARMONY_NULL_NULL","text":{"KOREA":"앉으시죠. 미사가 아니면 골방에 틀어박혀 사는지라 대접할 건 없습니다만.","JPN":"どうぞお座りください。ミサでなければ部屋に閉じこもっているばかりですので、おもてなしできるようなものはありませんが。","ENG":"Please, have a seat. Since I seldom leave the small room of mine except for Mass, I am afraid I do not have much to offer.","TWN":"請坐。沒有彌撒的時候，我都待在房裡，所以沒什麼可以招待的。"},"stage":{"bg":"LABORATORY_02","bgm":"CUTSCENE_TRAGEDY_HARD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CONDUCT_HARMONY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"MORS_SHADOW_ARMOR_NULL","text":{"KOREA":"아니. 용건만 말하마. 이 공기 속에서 더 오래 있길 원치 않으니.","JPN":"いや。用件だけ言おう。これ以上この空気の中にいたくはないのでな。","ENG":"We shall speak only of the business at hand. I do not wish to breathe this air any longer than I must.","TWN":"不需要，我說完就走，我也不想在這裡久待。"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_TRAGEDY_HARD","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L41_1","type":"dialog","speaker":"MORS_SHADOW_ARMOR_NULL","text":{"KOREA":"다른 추기경들과 네 연구에 대하여 논의하였다.","JPN":"他の枢機卿とそなたの研究について議論した。","ENG":"Your studies were discussed with other cardinals.","TWN":"我和其他樞機主教討論過你的研究。"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_TRAGEDY_HARD","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L42_1","type":"dialog","speaker":"CONDUCT_HARMONY_NULL_NULL","text":{"KOREA":"그렇군요. 처형으로 의견을 모으셨던가요.","JPN":"そうですか。処刑で意見が一致しましたか？","ENG":"I see. Was an execution agreed upon?","TWN":"原來如此，你們一致決定要處死我嗎？"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_TRAGEDY_HARD","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L44_1","type":"dialog","speaker":"MORS_SHADOW_ARMOR_NULL","text":{"KOREA":"추기경들의 고견을 받아들여, 네가 진행한 연구에 책임을 묻지 않도록 하였다.","JPN":"枢機卿の意向を受け入れ、そなたが行った研究について責任を問わぬこととした。","ENG":"The cardinals’ opinions. They do not hold you responsible for your research.","TWN":"樞機主教們一致決定，不會對你的研究問責。"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_TRAGEDY_HARD","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L45_1","type":"dialog","speaker":"CONDUCT_HARMONY_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"…","TWN":"……"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_TRAGEDY_HARD","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L46_1","type":"dialog","speaker":"MORS_SHADOW_ARMOR_NULL","text":{"KOREA":"아울러……. 교단 차원에서 지원을 논의하자더군.","JPN":"併せて……教団からの支援を議論しようと言っていた。","ENG":"In addition, they said we should discuss support for your research at the Order level.","TWN":"而且……教團方面想跟你討論支援的事。"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_TRAGEDY_HARD","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L47_1","type":"dialog","speaker":"CONDUCT_HARMONY_NULL_NULL","text":{"KOREA":"저는 제 연구 자료만 교단에서 활용되어도 무방하다고 여겼습니다만.","JPN":"私は研究資料だけ教団に使われてもいいと思っていたのですが。","ENG":"I would not have minded if the Order had chosen only my research materials.","TWN":"我是可以將我的研究資料提供教團使用。"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_TRAGEDY_HARD","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L48_1","type":"dialog","speaker":"MORS_SHADOW_ARMOR_NULL","text":{"KOREA":"네가 없이는 연구에 진척을 얻을 수 없다는 것이 추기경들의 공통된 의견이었다.","JPN":"そなたなしで研究の進捗を期待できないというのが枢機卿の共通意見であった。","ENG":"The common opinion of the cardinals was that progress could not continue on your research without you.","TWN":"樞機主教們一致認為，若沒有你將無法取得研究進度。"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_TRAGEDY_HARD","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L49_1","type":"dialog","speaker":"CONDUCT_HARMONY_NULL_NULL","text":{"KOREA":"교단에서 저와 같은 자를 중히 여겨 주시니 황송할 따름이군요.","JPN":"教団で私のような者を大事に思ってくださるなんて、光栄です。","ENG":"I am overjoyed to hear that the Order values people like me.","TWN":"真是受寵若驚，教團居然如此重視我。"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_TRAGEDY_HARD","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L50_1","type":"dialog","speaker":"CONDUCT_HARMONY_NULL_NULL","text":{"KOREA":"즉위하신 뒤에도 교단을 위해 전력으로 보필하겠습니다. 예하.","JPN":"即位の後も教団のために全力を尽くしてお仕え申し上げます。猊下。","ENG":"Even after the enthronement, I will do my utmost for the Order. Eminence.","TWN":"主教就任後，我也將盡全力輔佐教團。"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_TRAGEDY_HARD","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L4_1","type":"dialog","speaker":"MORS_SHADOW_ARMOR_NULL","text":{"KOREA":"그리고…….","JPN":"それから……","ENG":"Furthermore...","TWN":"還有……"},"stage":{"bg":"LABORATORY_02","bgm":"CUTSCENE_TRAGEDY_HARD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CONDUCT_HARMONY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"MORS_SHADOW_ARMOR_NULL","text":{"KOREA":"그 아이에게는, 결코 이 이야기가 새어나가선 안 된다.","JPN":"あの子には、決してこの話が漏れてはいけない。","ENG":"That child should never know of this.","TWN":"這件事絕對不能對那孩子洩漏半點風聲。"},"stage":{"bg":"LABORATORY_02","bgm":"CUTSCENE_TRAGEDY_HARD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CONDUCT_HARMONY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"CONDUCT_HARMONY_NULL_NULL","text":{"KOREA":"그 이교도 아이가 무서우십니까?","JPN":"あの異教徒の子を怖がっていらっしゃるのですか？","ENG":"Are you afraid of that pagan child?","TWN":"主教是害怕那個異教徒嗎？"},"stage":{"bg":"LABORATORY_02","bgm":"CUTSCENE_TRAGEDY_HARD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CONDUCT_HARMONY_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"MORS_SHADOW_ARMOR_NULL","text":{"KOREA":"자매를 찾겠다는 일념으로 타기리온에게 맞선 아이다.","JPN":"姉妹を探すという一念でタギリオンに立ち向かった子だ。","ENG":"The child faced Thagirion with the determination to find her sister.","TWN":"她是靠著要找到姊姊信念去對抗塔基里翁的，"},"stage":{"bg":"MAINSTREAM_124010","bgm":"CUTSCENE_TRAGEDY_HARD","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L11_1","type":"dialog","speaker":"MORS_SHADOW_ARMOR_NULL","text":{"KOREA":"교단의 실험에 희생되었다는 사실을 알게 되면……. 더 이상 살아갈 수 없을 터.","JPN":"教団の実験の犠牲になったと知れば……これ以上は生きていけまい。","ENG":"If she discovers the truth of the Order’s experiment... She will not be able to bear living any longer.","TWN":"萬一被她知道，她姊姊是因為教團的實驗而犧牲……她如何有動力繼續活下去？"},"stage":{"bg":"MAINSTREAM_124010","bgm":"CUTSCENE_TRAGEDY_HARD","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L12_1","type":"dialog","speaker":"CONDUCT_HARMONY_NULL_NULL","text":{"KOREA":"……그렇군요. 죽기 전에 어떻게 사과해야 할지 고민 중이었는데 말이죠.","JPN":"……そうですね。死ぬ前にどう謝るべきかと悩んでおりましたが。","ENG":"...I see. I had been thinking about how to apologize for it before I die.","TWN":"……原來是這樣，我最近在想，在我死之前該如何謝罪呢。　"},"stage":{"bg":"MAINSTREAM_124010","bgm":"CUTSCENE_TRAGEDY_HARD","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L15_1","type":"dialog","speaker":"MORS_SHADOW_ARMOR_NULL","text":{"KOREA":"가증스러운 소리는 집어치워라.","JPN":"憎たらしいことを言うな。","ENG":"Cease such hateful noise.","TWN":"收起你的違心之論。"},"stage":{"bg":"LABORATORY_02","bgm":"CUTSCENE_TRAGEDY_HARD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CONDUCT_HARMONY_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L16_1","type":"dialog","speaker":"CONDUCT_HARMONY_NULL_NULL","text":{"KOREA":"교단의 수용소가 어떤 곳인지 아시지 않습니까?","JPN":"教団の収容所がどんなところがご存じではありませんか。","ENG":"Do you not know what the Order’s concentration camps are like?","TWN":"主教也知道教團的收容所是什麼樣的地方吧？"},"stage":{"bg":"LABORATORY_02","bgm":"CUTSCENE_TRAGEDY_HARD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CONDUCT_HARMONY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"MORS_SHADOW_ARMOR_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"…","TWN":"……"},"stage":{"bg":"LABORATORY_02","bgm":"CUTSCENE_TRAGEDY_HARD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CONDUCT_HARMONY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"CONDUCT_HARMONY_NULL_NULL","text":{"KOREA":"교단을 거역한 이유로 그곳에서 말라 죽어가던 이들에게 기회를 주었을 뿐입니다.","JPN":"教団に逆らったという理由で、そこで痩せて死んでいく者たちに機会を与えたまでです。","ENG":"It merely gave opportunity to those who were dying because of their disobedience to the Order.","TWN":"只要違抗教團，就會被關到那個地方等死，而我只是給他們一個機會而已。"},"stage":{"bg":"LABORATORY_02","bgm":"CUTSCENE_TRAGEDY_HARD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CONDUCT_HARMONY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"CONDUCT_HARMONY_NULL_NULL","text":{"KOREA":"수용소의 실상은, 부모를 버리고 개종한 제가 가장 잘 알고 있으니까요.","JPN":"収容所の実体は、親を捨て宗旨替えした私が一番よく知っておりますから。","ENG":"I know best the realities of that camp as I abandoned my parents and converted.","TWN":"我是最知道收容所的情況的，畢竟我背棄父母改變信仰。"},"stage":{"bg":"LABORATORY_02","bgm":"CUTSCENE_TRAGEDY_HARD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CONDUCT_HARMONY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"MORS_SHADOW_ARMOR_NULL","text":{"KOREA":"끝까지…… 네게 죄가 없다고 변명할 셈인가?","JPN":"最後まで……自分には何の罪もないと言いわけするつもりか？","ENG":"To the end... You plead that you are innocent?","TWN":"你還是堅持……你沒有罪嗎？"},"stage":{"bg":"LABORATORY_02","bgm":"CUTSCENE_TRAGEDY_HARD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CONDUCT_HARMONY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"CONDUCT_HARMONY_NULL_NULL","text":{"KOREA":"죄인입니다. 허나 교단의 광활한 영토를 지킬 다른 방안이 있다면 제안해 주시죠.","JPN":"私は罪人です。ですが、教団の広大な領土を守れる代案がございましたらご提案くださいませ。","ENG":"I am a sinner. But if there is any other way to protect the vast territory of the Order, please do suggest it.","TWN":"我有罪，但若是有其他方法可以保住教團的領地，請告訴我。"},"stage":{"bg":"LABORATORY_02","bgm":"CUTSCENE_TRAGEDY_HARD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CONDUCT_HARMONY_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"CONDUCT_HARMONY_NULL_NULL","text":{"KOREA":"안타깝지만, 대안 없이 도덕률만 바라보는 비판은 수용할 수 없습니다. 예하.","JPN":"残念ながら、代案もなく道徳律のみを良しとする批判は受け入れられません。猊下。","ENG":"It is regrettable but, any argument based on moral law cannot be accepted without an alternative provided. Eminence.","TWN":"很抱歉，若是沒有其他替代方案，恕我無法接受滿口仁義道德的批判。"},"stage":{"bg":"LABORATORY_02","bgm":"CUTSCENE_TRAGEDY_HARD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CONDUCT_HARMONY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"MORS_SHADOW_ARMOR_NULL","text":{"KOREA":"……그래. 나 역시 네가 그리 나올 줄 알고 있었다.","JPN":"……そうか。我もそなたがそう出るとわかっていた。","ENG":"...Very well. I knew that would be your defense.","TWN":"……嗯，我早就知道你會這麼說。"},"stage":{"bg":"LABORATORY_02","bgm":"CUTSCENE_TRAGEDY_HARD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CONDUCT_HARMONY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"MORS_SHADOW_ARMOR_NULL","text":{"KOREA":"지난 회의에서 성황직을 받아들이기로 하였다.","JPN":"前回の会議で聖皇職を受け入れることにした。","ENG":"At the last meeting, I have accepted the papacy.","TWN":"上次的會議中，我已經決定要接受教皇的職分。"},"stage":{"bg":"LABORATORY_02","bgm":"CUTSCENE_TRAGEDY_HARD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CONDUCT_HARMONY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"MORS_SHADOW_ARMOR_NULL","text":{"KOREA":"추기경들의 뜻을 바꿀 수 없다면, 권위의 힘을 빌려서라도 이 만행을 멈추도록 하마.","JPN":"枢機卿の意を変えられないのなら、権威の力を借りてでもこの蛮行を止めようではないか。","ENG":"If I cannot change the cardinals’ minds, I shall use the power of authority to put an end to this atrocity.","TWN":"若是無法改變樞機主教們的決定，我也會用教皇的力量來阻止這個暴行。"},"stage":{"bg":"LABORATORY_02","bgm":"CUTSCENE_TRAGEDY_HARD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CONDUCT_HARMONY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"CONDUCT_HARMONY_NULL_NULL","text":{"KOREA":"참으로 딱하신 분이로군요. 역병이 아니었으면 이런 갈등에 처할 일도 없으셨으련만.","JPN":"本当に気の毒なお方です。疫病さえなければこのように葛藤することもなかったでしょうに。","ENG":"In an Era of confusion due to the plague, it is a pity that even good people like you are involved in such dirty work.","TWN":"真是可憐，要不是瘟疫的關係，她也不用落入這種進退兩難的困境。"},"stage":{"bg":"LABORATORY_02","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CONDUCT_HARMONY_NULL_NULL","face":"UNIT_PRIDE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L33_1","type":"dialog","speaker":"CONDUCT_HARMONY_NULL_NULL","text":{"KOREA":"그렇지 않나요, <color=#ffd34c>마에스트로?</color>","JPN":"そうではありませんか？　<color=#ffd34c>マエストロ</color>。","ENG":"Is that not so, <color=#ffd34c>Maestra?</color>","TWN":"你說是不是，<color=#ffd34c>指揮家？</color>"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AGENT_GRONIA_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"AGENT_GRONIA_NULL_NULL","text":{"KOREA":"헉……!! 헉……! 허억……!","JPN":"はっ……！！　はあ……！　はあ……！","ENG":"*Huff…!* *Huff…!* *Huff…!*","TWN":"呼……！！呼……！呼呼……！"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AGENT_GRONIA_NULL_NULL","face":"UNIT_HATE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L38_1","type":"dialog","speaker":"AGENT_GRONIA_NULL_NULL","text":{"KOREA":"총상이…… 아문 자국밖에 없어?","JPN":"銃傷が……癒えた跡しか残っていない？","ENG":"The gunshot wound... Just a few traces, but nothing else?","TWN":"我身上的槍傷……怎麼都只剩疤痕？"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AGENT_GRONIA_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"AGENT_GRONIA_NULL_NULL","text":{"KOREA":"옷은 피에 젖어 있는데……. 대체 어떻게 된 거지?","JPN":"服は血まみれなのに……一体どういうこと？","ENG":"But my clothes are soaked in blood... What happened?","TWN":"衣服上明明有血……這到底是怎麼回事？"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AGENT_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L42_1","type":"dialog","speaker":"AGENT_GRONIA_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"…","TWN":"……"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L45_1","type":"dialog","speaker":"AGENT_GRONIA_NULL_NULL","text":{"KOREA":"네, 국장님. 말씀하세요.","JPN":"はい、局長。","ENG":"Yes, Chief.","TWN":"是，部長請說。"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AGENT_GRONIA_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"SIR_GRONIA_NULL_NULL","face":"UNIT_IDLE"}}},"sfx":"FX_CUTSCEN_BEEP"},{"id":"L46_1","type":"dialog","speaker":"SIR_GRONIA_NULL_NULL","text":{"KOREA":"연락도 안 받아서 죽은 줄 알았더니……. 자네 정말 살아 있었군.","JPN":"電話にも出ないので死んだかと思ったが……本当に生きていたんだな。","ENG":"You weren’t picking up the phone, so I thought you were dead... Yet it appears you still live.","TWN":"剛打電話都沒接，我還以為你已經香消玉殞……沒想到你還活著。"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AGENT_GRONIA_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"SIR_GRONIA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L47_1","type":"dialog","speaker":"AGENT_GRONIA_NULL_NULL","text":{"KOREA":"그러게요. 깜빡 잠든 사이에 요정이 약이라도 발라 주고 갔나 보네요.","JPN":"そうですね。うっかり寝ている間に、妖精が薬でも塗ってくれたようです。","ENG":"Looks like it. Someone must have applied some magical medicine to me while I was asleep.","TWN":"我也很意外，可能是有天使趁我睡著的時候，幫我擦藥吧？"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AGENT_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SIR_GRONIA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L48_1","type":"dialog","speaker":"AGENT_GRONIA_NULL_NULL","text":{"KOREA":"포대는 탈환했습니다. 워낙 난장판이라 치우려면 고생 좀 하겠어요.","JPN":"砲台は奪還しました。修羅場過ぎて片付けるのに一苦労しそうですね。","ENG":"The turret has been recaptured. Things are still a bit of a mess over there, it’ll take some time to clean everything up.","TWN":"砲台我搶回來了，不過狀態滿糟的，修理可能會需要費滿大的功夫。"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AGENT_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SIR_GRONIA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L49_1","type":"dialog","speaker":"SIR_GRONIA_NULL_NULL","text":{"KOREA":"……그렇군.","JPN":"……そうか。","ENG":"I see...","TWN":"……原來如此。"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AGENT_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SIR_GRONIA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L50_1","type":"dialog","speaker":"SIR_GRONIA_NULL_NULL","text":{"KOREA":"저격수의 행적을 파악했다. 상황을 확인하러 간 요원들의 연락이 모두 동시에 두절됐어.","JPN":"スナイパーの足取りをつかんだ。同時に、状況把握のために派遣した要員全員から連絡が途絶えた。","ENG":"We’ve discovered the sniper’s whereabouts. We’ve lost contact with every agent that went to confirm the location.","TWN":"我們已經掌握到狙擊手的下落，但前往現場確認的幹員同時間音訊全無。"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AGENT_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SIR_GRONIA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L1_1","type":"dialog","speaker":"AGENT_GRONIA_NULL_NULL","text":{"KOREA":"네. 혼자 있진 않다면 그 일당도 보통내기는 아닐 겁니다.","JPN":"はい。一人じゃないとしたら、その一党も一筋縄ではいかないはずです。","ENG":"Yes. If she is not alone, then whoever she has with her is quite formidable as well.","TWN":"嗯，她若不是一個人，其他人也不是省油的燈。"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AGENT_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SIR_GRONIA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L3_1","type":"dialog","speaker":"AGENT_GRONIA_NULL_NULL","text":{"KOREA":"그래서, 위치가 어디죠?","JPN":"それで、どこですか？","ENG":"So, what’s the location?","TWN":"所以她的位置在哪裡？"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AGENT_GRONIA_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}}]`);export{e as default};